export const studyGuide = [{"title": "1. Foundations of Software Engineering", "topic": "Foundations", "overview": "Software engineering is the discipline concerned with producing, maintaining, and evolving software systematically. The lecturer material stresses that software is abstract and intangible, which removes physical manufacturing limits but allows complexity to grow quickly.", "subtopics": [["Definition of software engineering", "Concerned with all aspects of software production from specification through maintenance."], ["Why the field emerged", "The software crisis showed that large systems were late, unreliable, and more expensive than expected."], ["Nature of software", "Software does not wear out like hardware; it deteriorates as change accumulates and complexity grows."], ["Professional software", "Usually built by teams for users other than the developer and maintained over a long lifetime."], ["Core activities", "Specification, development, validation, and evolution; process frameworks often present communication, planning, modeling, construction, and deployment."], ["Good software attributes", "Maintainability, dependability/security, efficiency, and acceptability/usability."]], "exam_tip": "If asked 'What is software engineering?' define it, then add the full life-cycle scope: specification, development, validation, and maintenance/evolution.", "common_trap": "Do not say software engineering is only coding. The files repeatedly frame it as broader than programming.", "summary": "High-yield summary: define the field, explain the software crisis, state why software deteriorates, and list the fundamental activities and essential attributes."}, {"title": "2. Software Products and Product Thinking", "topic": "Software Products", "overview": "The lecturer notes distinguish project-based software from product software engineering. Project-based work starts from customer requirements, while product development starts from an identified business opportunity.", "subtopics": [["Generic vs custom software", "Generic software serves many customers; custom software is built for one client or organization."], ["Project-based software", "Driven by client-owned requirements; requirements often change during the project."], ["Product software engineering", "Driven by market opportunity, planned features, and roadmaps."], ["Product vision", "A simple statement that defines the essence of the product."], ["Platforms", "Products that provide functionality on which other applications can be built."], ["Feature creep", "Adding requested features without checking broad usefulness or better design alternatives."], ["Rapid delivery", "Important because market timing and user feedback matter in product success."]], "exam_tip": "In theory questions, contrast project-based and product software directly: starting point, ownership of change, and market pressure.", "common_trap": "Do not confuse a feature with a scenario or story. The test tutorial treats them as different concepts.", "summary": "High-yield summary: know generic vs custom, project-based vs product, product vision, platform, product manager, and feature creep."}, {"title": "3. Agile Software Engineering, Scrum, and XP", "topic": "Agile", "overview": "Agile development emphasizes flexibility, customer collaboration, and small working increments. The uploaded tutorial highlights the manifesto wording and the priority of software over excessive documentation.", "subtopics": [["Agility", "Ability to respond quickly and effectively to change."], ["Manifesto ideas", "Better ways of developing software, working software, customer collaboration, and responding to change."], ["Incremental delivery", "Useful software is delivered in small pieces rather than one final release."], ["When agile fits", "Changing requirements, close stakeholder access, and fast feedback cycles."], ["When agile may not fit", "Highly regulated or safety-critical environments that require heavy formality."], ["Scrum basics", "Product backlog, sprint, daily scrum, and increment."], ["XP basics", "Communication, simplicity, feedback, courage, respect, and disciplined engineering practices."]], "exam_tip": "For essay questions, connect agility to faster development and deployment by mentioning short cycles, feedback, reprioritization, and incremental release.", "common_trap": "Do not write that agile rejects documentation completely. The value statement is 'working software over comprehensive documentation,' not documentation versus no documentation.", "summary": "High-yield summary: define agility, state the manifesto priorities, name Scrum artifacts/events, and explain why agile can accelerate delivery."}, {"title": "4. Features, Scenarios, Stories, and User Focus", "topic": "Features, Stories, Scenarios", "overview": "The lecturer tutorial repeatedly tests the distinctions among feature, scenario, story, and product vision. These concepts connect user-centered thinking to product design.", "subtopics": [["Feature", "An element that implements a coherent set of functionality."], ["Scenario", "A narrative describing how a user or group of users may use the system."], ["Story", "A short user-centered requirement statement."], ["Persona", "A representation of a typical user used to think through needs and interaction."], ["Feature qualities", "Independence, coherence, and relevance."], ["UI simplicity", "Interfaces should not be unnecessarily complex."], ["Feature design knowledge", "User knowledge, domain knowledge, product knowledge, and technology knowledge."]], "exam_tip": "When asked to define scenario, use the phrase 'narrative that describes how a user or group of users might use a system.'", "common_trap": "Do not define product vision as a feature list. It is the essence of the product, not the full backlog.", "summary": "High-yield summary: be ready to distinguish feature, story, scenario, persona, and product vision in one sentence each."}, {"title": "5. Process Models and Software Evolution", "topic": "Process Models", "overview": "Past questions repeatedly test process models. The textbook and exams cover waterfall, incremental, prototyping, spiral, concurrent, component-based development, formal methods, and the Unified Process.", "subtopics": [["Waterfall", "Linear, sequential progression through major activities."], ["Incremental", "Delivery in a series of usable increments."], ["Prototyping", "Early working version used to clarify or explore requirements."], ["Spiral", "Risk-driven, iterative process combining prototyping and staged control."], ["Concurrent model", "Activities proceed in parallel and can exist in different states."], ["Component-based development", "Reuse through component qualification, adaptation, and integration."], ["Formal methods", "Mathematical specification and verification."], ["Unified Process", "Iterative framework with phases such as inception, elaboration, construction, and transition."], ["Prescriptive vs evolutionary", "Prescriptive emphasizes planned structure; evolutionary emphasizes change through repeated cycles."], ["Software evolution", "Software changes after delivery to stay useful and aligned with needs."]], "exam_tip": "Many questions ask for benefits, problems, or examples. Always state where the model fits best, not only what it is.", "common_trap": "Do not say UML and the Unified Process are the same. One is a modeling language; the other is a process framework.", "summary": "High-yield summary: know each model's defining idea, major advantage, likely drawback, and a suitable project context."}, {"title": "6. Requirements Engineering", "topic": "Requirements Engineering", "overview": "Requirements engineering is one of the heaviest recurring exam topics. The files emphasize tasks such as elicitation, analysis, negotiation, validation, and management, as well as the outline of an SRS.", "subtopics": [["Stakeholders", "People or groups who affect or are affected by the system."], ["Elicitation", "Gathering information about needs, goals, constraints, and context."], ["Analysis and modeling", "Organizing, refining, and representing requirements."], ["Negotiation", "Reconciling conflicts and reaching a realistic agreed set of requirements."], ["Validation", "Checking correctness, completeness, consistency, realism, and testability."], ["Management", "Handling changes and preserving traceability."], ["Requirement types", "User, system, functional, non-functional, and domain requirements."], ["SRS outline", "A structured requirements document describing services, constraints, assumptions, and models."], ["Multiple stakeholder problem", "Different stakeholders often have conflicting priorities, terminology, and expectations."], ["Work products", "Statements of need, meeting records, scenarios, use cases, and preliminary models."]], "exam_tip": "For 'list and explain the tasks' questions, present the tasks in order and attach one line of purpose to each.", "common_trap": "Do not reduce validation to spelling checks. Validation is about whether the requirements are the right and workable ones.", "summary": "High-yield summary: memorize the task flow, the five requirement categories, common stakeholder conflicts, and the purpose of the SRS."}, {"title": "7. Modeling and UML", "topic": "Modeling and UML", "overview": "The exam papers repeatedly ask for scenario-based, data, class-oriented, flow-oriented, and behavioral models, plus specific UML diagrams such as class, activity, and state diagrams.", "subtopics": [["Scenario-based model", "Use cases and usage narratives."], ["Data model", "Data objects, attributes, and relationships."], ["Class-oriented model", "Classes, attributes, operations, and associations."], ["Flow-oriented model", "How information moves and is transformed."], ["Behavioral model", "Events, states, and responses over time."], ["Class diagrams", "Static structure of classes and relationships."], ["Activity diagrams", "Workflow, process steps, and branching."], ["State diagrams", "State changes triggered by events."], ["Structural vs behavioral", "Static organization versus dynamic change."], ["Model-driven engineering", "Placing models at the center of development, sometimes with automated transformation."]], "exam_tip": "ATM questions often require use case, class, and activity diagrams together. Identify actors, key domain entities, and the transaction flow.", "common_trap": "Do not confuse class diagrams with activity diagrams. Class diagrams are static; activity diagrams show flow.", "summary": "High-yield summary: define the five analysis model types and know when to use class, activity, and state diagrams."}, {"title": "8. Design Concepts and Software Architecture", "topic": "Design and Architecture", "overview": "The files ask repeatedly about architecture and design concepts such as abstraction, patterns, separation of concerns, modularity, refinement, information hiding, and refactoring.", "subtopics": [["Architecture definition", "The fundamental organization of a system, its components, relationships, and design/evolution principles."], ["Layered architecture", "Organizes system services into layers with controlled interaction."], ["Pipe-and-filter", "Transforms data through connected processing stages."], ["Data/class design", "Defines data structures and classes."], ["Interface design", "Defines interactions with users and among components."], ["Abstraction", "Suppressing detail to focus on essentials."], ["Modularity", "Decomposition into manageable parts."], ["Separation of concerns", "Handling different concerns independently."], ["Information hiding", "Concealing likely-to-change details behind interfaces."], ["Refinement and refactoring", "Developing detail in steps and improving design without changing external behavior."], ["Patterns", "Reusable design solutions to recurring problems."]], "exam_tip": "For theory essays, do not merely list the concepts. Tie each concept to why it improves understandability, changeability, or quality.", "common_trap": "Do not treat architecture as just a diagram. The lecturer tutorial includes organization, relationships, environment, and guiding principles.", "summary": "High-yield summary: define architecture properly, then explain abstraction, modularity, separation of concerns, information hiding, refinement, refactoring, and patterns."}, {"title": "9. Cloud-Based Software, Microservices, Security, and Reliability", "topic": "Cloud, Microservices, Security, Reliability", "overview": "The lecturer outline explicitly includes cloud-based software, microservices architecture, security/privacy, and reliable programming. The later slides also discuss SaaS design issues and DevOps links.", "subtopics": [["Cloud-based software", "Software delivered from remote infrastructure over a network."], ["SaaS design issues", "Data regulation, data transfer limits, data security, and data exchange via APIs."], ["Authentication", "May be local, social-login based, or federated for enterprise use."], ["Information leakage risk", "Multi-organization systems must prevent cross-customer leakage."], ["Multi-tenant vs multi-instance", "One shared instance versus separate system/database copies."], ["Microservices", "Small independently deployable services that collaborate."], ["Reliability", "Consistent required operation over time."], ["Safety and privacy", "Avoiding harm and protecting personal information."]], "exam_tip": "If the question looks modern or service-oriented, connect cloud design issues to regulation, authentication, security, and deployment.", "common_trap": "Do not assume cloud always means better security. The lecturer material explicitly warns against that assumption.", "summary": "High-yield summary: know SaaS risks, multi-tenant vs multi-instance, authentication options, and the meaning of reliability, safety, and privacy."}, {"title": "10. Quality, Testing, DevOps, Teams, and Ethics", "topic": "Quality and Testing", "overview": "Quality and testing recur in several years of past questions. The lecturer material also adds DevOps and code management. Team structure, the four Ps, team toxicity, and ethical principles round out the project-focused part of the course.", "subtopics": [["Software quality", "Meeting requirements and implicit expectations."], ["Garvin dimensions and other quality factors", "Ways of evaluating product quality."], ["Quality dilemma", "Pressure on time and cost can conflict with quality goals."], ["Cost of quality", "Prevention, appraisal, internal failure, and external failure."], ["Achieving quality", "Methods, project management, quality control, and quality assurance."], ["Testing levels", "Unit, integration, validation, and system testing."], ["Verification vs validation", "Built right versus built for the right need."], ["DevOps", "Integration of development, deployment, and support."], ["Source code management", "Shared repositories, version history, branching, and merging."], ["Continuous integration/deployment", "Frequent automated integration and, where feasible, automated release."], ["Four Ps", "People, Product, Process, Project."], ["Team toxicity and ethics", "Avoid destructive environments; act with honesty, integrity, competence, and responsibility."]], "exam_tip": "Quality essays score better when you connect quality activities to cost and risk, not only to testing.", "common_trap": "Do not equate SQA with testing alone. SQA is broader and includes standards, plans, reviews, and process assurance.", "summary": "High-yield summary: define quality, list cost-of-quality parts, distinguish testing levels, explain DevOps basics, and remember the four Ps and team toxicity."}];
